import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  ChevronLeft, ChevronRight, Trash2, X, Save, 
  ShoppingBag, Receipt, Hash, CreditCard, User, Calendar 
} from 'lucide-react';
import ModalFeedback from '../components/ModalFeedback';
import '../styles/Listagem.css';

const Listagem = () => {
  const [despesas, setDespesas] = useState([]);
  const [cartoes, setCartoes] = useState([]);
  const [usuarios, setUsuarios] = useState([]); 
  const [perfilLogado, setPerfilLogado] = useState(null);
  const [itemParaEditar, setItemParaEditar] = useState(null);
  const [modal, setModal] = useState({ isOpen: false, type: 'success', title: '', message: '', onConfirm: null });
  const [filtroData, setFiltroData] = useState({ mes: new Date().getMonth(), ano: new Date().getFullYear() });

  const mesesNominais = ["Janeiro", "Fevereiro", "Março", "Abril", "Maio", "Junho", "Julho", "Agosto", "Setembro", "Outubro", "Novembro", "Dezembro"];
  const formasPagamento = ["Boleto", "Crédito", "Débito", "Dinheiro", "Pix", "Transferência"].sort();

  useEffect(() => { carregarDadosIniciais(); }, [filtroData]);

  // Função para formatar NF (123.456.789)
  const formatarNF = (valor) => {
    const apenasNumeros = valor.replace(/\D/g, '').slice(0, 9);
    return apenasNumeros
      .replace(/(\d{3})(\d)/, '$1.$2')
      .replace(/(\d{3})(\d)/, '$1.$2');
  };

  async function carregarDadosIniciais() {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;
    const { data: meuPerfil } = await supabase.from('profiles').select('*').eq('id', user.id).single();
    setPerfilLogado(meuPerfil);
    
    if (meuPerfil?.tipo_usuario === 'proprietario') {
      const { data: dCartoes } = await supabase.from('cartoes').select('id, nome').order('nome');
      const { data: dUsers } = await supabase.from('profiles').select('id, nome').order('nome');
      setCartoes(dCartoes || []);
      setUsuarios(dUsers || []);
    }
    fetchDespesas(meuPerfil);
  }

  async function fetchDespesas(perfil) {
    let query = supabase.from('compras').select('*, profiles(nome)').order('data_compra', { ascending: false });
    if (perfil?.tipo_usuario !== 'proprietario') query = query.eq('user_id', perfil.id);
    
    const { data, error } = await query;
    if (!error && data) {
      const projetadas = [];
      data.forEach(item => {
        const numParcelas = item.num_parcelas || 1;
        for (let i = 0; i < numParcelas; i++) {
          const [ano, mes, dia] = item.data_compra.split('-');
          const dataCompra = new Date(ano, mes - 1, dia);
          const dataParcela = new Date(dataCompra.getFullYear(), dataCompra.getMonth() + i, 1);
          
          if (dataParcela.getMonth() === filtroData.mes && dataParcela.getFullYear() === filtroData.ano) {
            projetadas.push({ 
              ...item, 
              parcelaAtual: i + 1, 
              valorParcela: parseFloat(item.valor_total) / numParcelas, 
              nomeResponsavel: item.profiles?.nome || '⚠️ Pendente' 
            });
          }
        }
      });
      setDespesas(projetadas);
    }
  }

  const handleUpdate = async (e) => {
    e.preventDefault();
    const isCredito = itemParaEditar.forma_pagamento === 'Crédito';

    const { error } = await supabase.from('compras').update({
      descricao: itemParaEditar.descricao,
      loja: itemParaEditar.loja,
      user_id: itemParaEditar.user_id, 
      valor_total: parseFloat(itemParaEditar.valor_total),
      forma_pagamento: itemParaEditar.forma_pagamento,
      cartao: isCredito ? itemParaEditar.cartao : 'À Vista',
      data_compra: itemParaEditar.data_compra,
      num_parcelas: isCredito ? parseInt(itemParaEditar.num_parcelas) : 1,
      parcelado: isCredito && parseInt(itemParaEditar.num_parcelas) > 1,
      pedido: itemParaEditar.pedido,
      nota_fiscal: itemParaEditar.nota_fiscal
    }).eq('id', itemParaEditar.id);

    if (error) {
      setModal({ isOpen: true, type: 'error', title: 'Erro', message: error.message });
    } else {
      setItemParaEditar(null);
      setModal({ isOpen: true, type: 'success', title: 'Atualizado', message: 'Lançamento editado com sucesso!' });
      fetchDespesas(perfilLogado);
    }
  };

  const confirmDelete = (id) => {
    setModal({
      isOpen: true,
      type: 'error',
      title: 'Excluir Gasto?',
      message: 'Isso removerá a compra e todas as parcelas futuras dela.',
      onConfirm: async () => {
        const { error } = await supabase.from('compras').delete().eq('id', id);
        if (!error) {
          setItemParaEditar(null);
          setModal({ isOpen: true, type: 'success', title: 'Excluído', message: 'Registro removido.' });
          fetchDespesas(perfilLogado);
        }
      }
    });
  };

  const mudarMes = (direcao) => {
    let novoMes = filtroData.mes + direcao;
    let novoAno = filtroData.ano;
    if (novoMes < 0) { novoMes = 11; novoAno--; }
    else if (novoMes > 11) { novoMes = 0; novoAno++; }
    setFiltroData({ mes: novoMes, ano: novoAno });
  };

  return (
    <div className="listagem-container">
      <div className="listagem-header">
        <div>
          <h2>Extrato de Gastos</h2>
          <p>{mesesNominais[filtroData.mes]} de {filtroData.ano}</p>
        </div>
        <div className="date-navigator">
          <button onClick={() => mudarMes(-1)} className="nav-btn"><ChevronLeft size={20} /></button>
          <div className="date-display">
            <span className="month-name">{mesesNominais[filtroData.mes].substring(0,3)}</span>
            <span className="year-name">{filtroData.ano}</span>
          </div>
          <button onClick={() => mudarMes(1)} className="nav-btn"><ChevronRight size={20} /></button>
        </div>
      </div>

      <div className="table-wrapper">
        <table className="custom-table">
          <thead>
            <tr>
              <th>Data</th>
              <th>Responsável</th>
              <th>Descrição</th>
              <th>Loja</th>
              <th>N° Pedido</th>
              <th>Nota Fiscal</th>
              <th>Pagamento</th>
              <th>Parcela</th>
              <th style={{ textAlign: 'right' }}>Valor Parcela</th>
            </tr>
          </thead>
          <tbody>
            {despesas.map((item, idx) => (
              <tr key={`${item.id}-${idx}`} 
                  className={perfilLogado?.tipo_usuario === 'proprietario' ? 'clickable-row' : ''} 
                  onClick={() => perfilLogado?.tipo_usuario === 'proprietario' && setItemParaEditar(item)}>
                <td className="cell-date">{item.data_compra.split('-').reverse().slice(0,2).join('/')}</td>
                <td className="cell-user">{item.nomeResponsavel}</td>
                <td className="cell-main">{item.descricao}</td>
                <td className="cell-sub">{item.loja}</td>
                <td className="cell-hash">{item.pedido || '-'}</td>
                <td className="cell-nf">{item.nota_fiscal || '-'}</td>
                <td>
                   <div className="main-text">{item.forma_pagamento}</div>
                   <div className="sub-text">{item.cartao}</div>
                </td>
                <td>
                  <span className={`badge-parcela ${item.parcelado ? 'is-parcelado' : 'is-avista'}`}>
                    {item.parcelado ? `${item.parcelaAtual}/${item.num_parcelas}` : 'À Vista'}
                  </span>
                </td>
                <td className="cell-value">
                  R$ {item.valorParcela.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {itemParaEditar && (
        <div className="edit-modal-overlay">
          <div className="edit-modal-content">
            <div className="modal-fixed-header">
              <h3>Editar Gasto</h3>
              <button onClick={() => setItemParaEditar(null)} className="btn-close"><X size={20}/></button>
            </div>

            <div className="modal-scrollable-body">
              <form id="edit-form" onSubmit={handleUpdate}>
                <div className="grid-form">
                  <div className="form-group">
                    <label><Calendar size={12}/> Data</label>
                    <input type="date" className="form-control" value={itemParaEditar.data_compra || ''} onChange={e => setItemParaEditar({...itemParaEditar, data_compra: e.target.value})} required />
                  </div>
                  <div className="form-group">
                    <label><User size={12}/> Responsável</label>
                    <select className="form-control" value={itemParaEditar.user_id || ''} onChange={e => setItemParaEditar({...itemParaEditar, user_id: e.target.value})} required>
                      {usuarios.map(u => <option key={u.id} value={u.id}>{u.nome}</option>)}
                    </select>
                  </div>
                  
                  <div className="form-group full-width">
                    <label>Descrição</label>
                    <input className="form-control" value={itemParaEditar.descricao} onChange={e => setItemParaEditar({...itemParaEditar, descricao: e.target.value})} required />
                  </div>

                  <div className="form-group">
                    <label>Loja</label>
                    <input className="form-control" value={itemParaEditar.loja || ''} onChange={e => setItemParaEditar({...itemParaEditar, loja: e.target.value})} />
                  </div>
                  <div className="form-group">
                    <label>Valor Total</label>
                    <input type="number" step="0.01" className="form-control" value={itemParaEditar.valor_total} onChange={e => setItemParaEditar({...itemParaEditar, valor_total: e.target.value})} required />
                  </div>

                  <div className="form-group">
                    <label><Hash size={12}/> N° Pedido</label>
                    <input className="form-control" value={itemParaEditar.pedido || ''} onChange={e => setItemParaEditar({...itemParaEditar, pedido: e.target.value})} />
                  </div>
                  <div className="form-group">
                    <label><Receipt size={12}/> Nota Fiscal</label>
                    <input 
                      className="form-control" 
                      placeholder="000.000.000"
                      value={itemParaEditar.nota_fiscal || ''} 
                      onChange={e => setItemParaEditar({...itemParaEditar, nota_fiscal: formatarNF(e.target.value)})} 
                    />
                  </div>

                  <div className="form-group">
                    <label>Pagamento</label>
                    <select className="form-control" value={itemParaEditar.forma_pagamento} onChange={e => setItemParaEditar({...itemParaEditar, forma_pagamento: e.target.value})}>
                      {formasPagamento.map(f => <option key={f} value={f}>{f}</option>)}
                    </select>
                  </div>

                  {itemParaEditar.forma_pagamento === 'Crédito' && (
                    <>
                      <div className="form-group">
                        <label><CreditCard size={12}/> Cartão</label>
                        <select className="form-control" value={itemParaEditar.cartao} onChange={e => setItemParaEditar({...itemParaEditar, cartao: e.target.value})}>
                          {cartoes.map(c => <option key={c.id} value={c.nome}>{c.nome}</option>)}
                        </select>
                      </div>
                      <div className="form-group">
                        <label>Parcelas</label>
                        <input type="number" className="form-control" value={itemParaEditar.num_parcelas || 1} onChange={e => setItemParaEditar({...itemParaEditar, num_parcelas: e.target.value})} />
                      </div>
                    </>
                  )}
                </div>
              </form>
            </div>

            <div className="modal-fixed-footer">
              <button type="submit" form="edit-form" className="btn-save"><Save size={18} /> Salvar Alterações</button>
              <button type="button" className="btn-delete" onClick={() => confirmDelete(itemParaEditar.id)} title="Excluir Registro">
                <Trash2 size={20} />
              </button>
            </div>
          </div>
        </div>
      )}

      <ModalFeedback 
        isOpen={modal.isOpen} type={modal.type} title={modal.title} message={modal.message}
        onClose={() => setModal({ ...modal, isOpen: false })} onConfirm={modal.onConfirm}
      />
    </div>
  );
};

export default Listagem;
